#include <iostream>
#include <string>
#include <vector>
#include <sstream>
#include <streambuf> // For std::streambuf

// This function assumes the student's solution is implemented in a function called 'solution_main'.
// The original 'main' function in the student's file should call 'solution_main'.
extern int solution_main(); // Forward declaration for the student's solution

std::string run_test_case(const std::string& input) {
    std::stringstream ss_input(input);
    std::stringstream ss_output;

    // Redirect cin and cout
    std::streambuf* old_cin = std::cin.rdbuf();
    std::streambuf* old_cout = std::cout.rdbuf();
    std::cin.rdbuf(ss_input.rdbuf());
    std::cout.rdbuf(ss_output.rdbuf());

    // Call the student's solution
    solution_main();

    // Restore cin and cout
    std::cin.rdbuf(old_cin);
    std::cout.rdbuf(old_cout);

    return ss_output.str();
}
